    if(id.includes('oak'))return'chop_oak';if(id.includes('willow'))return'chop_willow';if(id.includes('maple'))return'chop_maple';if(id.includes('yew'))return'chop_yew';if(id.includes('elder'))return'chop_elder';if(id.includes('ash')&&id.startsWith('chop'))return'chop_ashwood';
    if(id.includes('copper'))return'mine_copper';if(id.includes('tin'))return'mine_tin';if(id.includes('coal'))return'mine_coal';if(id.includes('mithril')&&id.startsWith('mine'))return'mine_mithril';if(id.includes('adamant')&&id.startsWith('mine'))return'mine_adamant';if(id.includes('obsidian')&&id.startsWith('mine'))return'mine_obsidian';if(id.includes('iron')&&id.startsWith('mine'))return'mine_iron';if(id.includes('essence'))return'mine_essence';if(id.includes('gold')&&id.startsWith('mine'))return'mine_gold';
